citeFormats.template:
{{bibliography}} 
[online]({{uri}}) [local]({{desktopURI}}) {%- for attachment in attachments | filterby("path", "endswith", ".pdf") %} [pdf](file://{{attachment.path | replace(" ", "%20")}})
{% if loop.last %} 
{% endif %}{%- endfor %}

[{%- if creators and creators.length > 0 -%}
(
  {%- for creator in creators -%}
    {%- if creator.name -%}
      {{creator.name}}
    {%- else -%}
       {{creator.lastName}}
    {%- endif -%}
    {% if not loop.last %},  {% endif %}
  {%- endfor -%}
{%- endif -%}
{%- if date -%}, {{date |  format("YYYY") }}){%- endif -%}
]
{%- if attachments and attachments.length > 0 -%}
    {%- set file = attachments | filterby("path", "endswith", ".pdf") | first -%}
    {%- if file and file.path and file.path.endsWith(".pdf") -%}
	(zotero://open-pdf/library/items/{{file.itemKey}}?page={{page}})
    {%- endif -%}
{%- endif -%}
